define('taoQtiTest/runner/proxy/cache/itemStore',['lodash', 'core/store', 'taoQtiTest/runner/proxy/cache/itemPreloader'], function (_, store, itemPreloaderFactory) {
  'use strict';

  _ = _ && Object.prototype.hasOwnProperty.call(_, 'default') ? _['default'] : _;
  store = store && Object.prototype.hasOwnProperty.call(store, 'default') ? store['default'] : store;
  itemPreloaderFactory = itemPreloaderFactory && Object.prototype.hasOwnProperty.call(itemPreloaderFactory, 'default') ? itemPreloaderFactory['default'] : itemPreloaderFactory;
  var defaultConfig = {
    itemTTL: 0,
    maxSize: 10,
    preload: false
  };
  function itemStoreFactory(options) {
    var config = _.defaults(options || {}, defaultConfig);
    var getStore = () => store('item-cache', store.backends.memory);
    var index = new Map();
    var lastIndexedPosition = 0;
    var isExpired = key => {
      var meta = index.get(key);
      if (meta) {
        return config.itemTTL && Date.now() - meta.timestamp >= config.itemTTL;
      }
      return false;
    };
    var findFirstIndexedItem = () => {
      var first = null;
      var lowest = Number.POSITIVE_INFINITY;
      index.forEach((item, key) => {
        if (item.position < lowest) {
          lowest = item.position;
          first = key;
        }
      });
      return first;
    };
    var findExpiredItems = () => {
      var expired = [];
      index.forEach((item, key) => {
        if (isExpired(key)) {
          expired.push(key);
        }
      });
      return expired;
    };
    var itemPreloader;
    if (config.preload) {
      itemPreloader = itemPreloaderFactory(_.pick(config, ['testId']));
    }
    return {
      setCacheSize(cacheSize) {
        config.maxSize = cacheSize;
      },
      setItemTTL(ttl) {
        config.itemTTL = ttl;
      },
      get(key) {
        if (!this.has(key)) {
          return Promise.resolve();
        }
        return getStore().then(itemStorage => itemStorage.getItem(key));
      },
      has(key) {
        return index.has(key) && !isExpired(key);
      },
      set(key, item) {
        return getStore().then(itemStorage => {
          return itemStorage.setItem(key, item).then(updated => {
            if (updated) {
              if (!index.has(key)) {
                index.set(key, {
                  position: lastIndexedPosition++,
                  timestamp: Date.now()
                });
              }
              if (config.preload) {
                _.defer(() => itemPreloader.preload(item));
              }
            }
            if (index.size > 1 && index.size > config.maxSize) {
              return this.remove(findFirstIndexedItem()).then(removed => updated && removed);
            }
            return updated;
          });
        });
      },
      update(key, updateKey, updateValue) {
        if (index.has(key) && _.isString(updateKey)) {
          return getStore().then(itemStorage => {
            return itemStorage.getItem(key).then(itemData => {
              if (_.isPlainObject(itemData)) {
                itemData[updateKey] = updateValue;
                return itemStorage.setItem(key, itemData);
              }
            });
          });
        }
        return Promise.resolve(false);
      },
      remove(key) {
        if (index.has(key)) {
          return getStore().then(itemStorage => {
            index.delete(key);
            return itemStorage.getItem(key).then(item => {
              if (config.preload) {
                _.defer(() => itemPreloader.unload(item));
              }
            }).then(() => itemStorage.removeItem(key));
          });
        }
        return Promise.resolve(false);
      },
      prune() {
        return Promise.all(findExpiredItems().map(this.remove));
      },
      clear() {
        return getStore().then(itemStorage => {
          index.clear();
          return itemStorage.clear();
        });
      }
    };
  }
  return itemStoreFactory;
});
